changeSet.sql:
CREATE TABLE nexus.pdf_pipeline ( tenant_id TEXT NOT NULL, content_hash TEXT NOT NULL, pdf_path TEXT NOT NULL, collection TEXT NOT NULL, total_pages INTEGER, pages_extracted INTEGER NOT NULL DEFAULT 0, chunks_created INTEGER, chunks_embedded INTEGER, chunks_uploaded INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL DEFAULT 'running', error TEXT NOT NULL DEFAULT '', extraction_meta TEXT NOT NULL DEFAULT '', started_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL, CONSTRAINT pdf_pipeline_pk PRIMARY KEY (tenant_id, content_hash) );
CREATE TABLE nexus.pdf_pages ( tenant_id TEXT NOT NULL, content_hash TEXT NOT NULL, page_index INTEGER NOT NULL, page_text TEXT NOT NULL, metadata_json TEXT NOT NULL DEFAULT '{}', created_at TIMESTAMPTZ NOT NULL, CONSTRAINT pdf_pages_pk PRIMARY KEY (tenant_id, content_hash, page_index) );
CREATE TABLE nexus.pdf_chunks ( tenant_id TEXT NOT NULL, content_hash TEXT NOT NULL, chunk_index INTEGER NOT NULL, chunk_text TEXT NOT NULL, chunk_id TEXT NOT NULL, metadata_json TEXT NOT NULL DEFAULT '{}', embedding BYTEA, uploaded BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL, CONSTRAINT pdf_chunks_pk PRIMARY KEY (tenant_id, content_hash, chunk_index) );

changeSet.rollback:
DROP TABLE IF EXISTS nexus.pdf_chunks CASCADE;
DROP TABLE IF EXISTS nexus.pdf_pages CASCADE;
DROP TABLE IF EXISTS nexus.pdf_pipeline CASCADE;

changeSet.sql:
ALTER TABLE nexus.pdf_pipeline ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.pdf_pipeline FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.pdf_pipeline
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

ALTER TABLE nexus.pdf_pages ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.pdf_pages FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.pdf_pages
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

ALTER TABLE nexus.pdf_chunks ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.pdf_chunks FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.pdf_chunks
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.pdf_chunks;
ALTER TABLE nexus.pdf_chunks NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.pdf_chunks DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.pdf_pages;
ALTER TABLE nexus.pdf_pages NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.pdf_pages DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.pdf_pipeline;
ALTER TABLE nexus.pdf_pipeline NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.pdf_pipeline DISABLE ROW LEVEL SECURITY;
